using System.ComponentModel;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Tool Implementations ---

var notes = new Dictionary<string, string>();

[Description("Search the web for information on a given query. Returns a list of relevant snippets.")]
string SearchWeb([Description("The search query")] string query)
{
    Console.WriteLine($"  [Tool] Searching the web for: \"{query}\"");

    // Simulate web search results. In production, replace with a real search API (Bing, Google, etc.)
    var results = query.ToLowerInvariant() switch
    {
        var q when q.Contains("quantum computing") => """
            1. Quantum computing uses qubits that can exist in superposition, enabling parallel computation.
            2. Major players include IBM (Eagle 127-qubit processor), Google (Sycamore), and Microsoft (topological qubits).
            3. Key applications: cryptography, drug discovery, optimization problems, and materials science.
            4. Current challenges: decoherence, error correction, and scaling qubit count.
            5. IBM plans a 100,000-qubit system by 2033. Google achieved quantum supremacy in 2019.
            """,
        var q when q.Contains("artificial intelligence") || q.Contains(" ai ") => """
            1. AI encompasses machine learning, deep learning, NLP, computer vision, and robotics.
            2. Large language models (GPT, Claude, Gemini) have transformed text generation and reasoning.
            3. AI is being applied in healthcare, autonomous vehicles, scientific research, and creative arts.
            4. Concerns include bias, job displacement, safety alignment, and energy consumption.
            5. Governments worldwide are developing AI regulation frameworks.
            """,
        var q when q.Contains("climate") => """
            1. Global temperatures have risen ~1.1°C above pre-industrial levels as of 2024.
            2. The Paris Agreement targets limiting warming to 1.5°C, requiring net-zero by 2050.
            3. Renewable energy capacity surpassed 3,800 GW globally in 2023.
            4. Key solutions: solar/wind energy, electrification, carbon capture, and reforestation.
            5. Extreme weather events are increasing in frequency and severity worldwide.
            """,
        _ => $"""
            1. "{query}" is an active area of research with multiple ongoing developments.
            2. Recent publications highlight new breakthroughs and applications in this field.
            3. Experts recommend further investigation into subtopics for comprehensive understanding.
            4. Several organizations and institutions are contributing to advancements in this area.
            5. Public interest and funding in this topic have increased significantly in recent years.
            """
    };

    return results;
}

[Description("Save a research note with a title. Use this to record key findings during research.")]
string TakeNote(
    [Description("A short title for the note")] string title,
    [Description("The content of the note")] string content)
{
    notes[title] = content;
    Console.WriteLine($"  [Tool] Note saved: \"{title}\"");
    return $"Note '{title}' saved successfully.";
}

[Description("Retrieve all saved research notes.")]
string GetNotes()
{
    if (notes.Count == 0)
        return "No notes have been saved yet.";

    Console.WriteLine($"  [Tool] Retrieving {notes.Count} note(s)");
    return string.Join("\n\n", notes.Select(n => $"## {n.Key}\n{n.Value}"));
}

// --- Agent Setup ---

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY") ?? "sk-placeholder";
var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

var openAiClient = new OpenAIClient(apiKey);

IChatClient chatClient = new ChatClientBuilder(openAiClient.GetChatClient(model).AsIChatClient())
    .UseFunctionInvocation()
    .Build();

var tools = new[]
{
    AIFunctionFactory.Create(SearchWeb),
    AIFunctionFactory.Create(TakeNote),
    AIFunctionFactory.Create(GetNotes),
};

var chatOptions = new ChatOptions { Tools = [.. tools] };

// --- Main Loop ---

Console.WriteLine("=== Research Agent ===");
Console.WriteLine("Enter a topic to research (or 'quit' to exit):");
Console.Write("> ");

while (Console.ReadLine() is { } input && !input.Equals("quit", StringComparison.OrdinalIgnoreCase))
{
    if (string.IsNullOrWhiteSpace(input))
    {
        Console.Write("> ");
        continue;
    }

    var messages = new List<ChatMessage>
    {
        new(ChatRole.System, """
            You are a research agent. Your job is to thoroughly research the given topic by:
            1. Searching the web for relevant information (use multiple searches with different queries)
            2. Taking notes on key findings as you go
            3. After gathering enough information, retrieve your notes and provide a comprehensive summary

            Always search at least 2-3 different angles of the topic, take notes on important findings,
            then synthesize everything into a clear, well-organized summary for the user.
            """),
        new(ChatRole.User, $"Please research the following topic and provide a summary: {input}")
    };

    Console.WriteLine($"\nResearching: {input}\n");

    var response = await chatClient.GetResponseAsync(messages, chatOptions);
    Console.WriteLine("\n--- Research Summary ---\n");
    Console.WriteLine(response.Text);
    Console.WriteLine("\n------------------------\n");

    notes.Clear();
    Console.Write("> ");
}

Console.WriteLine("Goodbye!");

